//! Debug KAT Analysis
//!
//! This module analyzes the actual KAT data to understand the expected values.

#[cfg(feature = "aes-drbg")]
use lib_q_hqc::aes_ctr_drbg::Aes256CtrDrbg;
#[cfg(feature = "aes-drbg")]
use rand_core::Rng;

/// Helper function to convert hex string to bytes
fn hex_to_bytes(hex: &str) -> Vec<u8> {
    let mut bytes = Vec::new();
    let mut chars = hex.chars().peekable();

    while let (Some(c1), Some(c2)) = (chars.next(), chars.next()) {
        let byte = u8::from_str_radix(&format!("{}{}", c1, c2), 16).unwrap();
        bytes.push(byte);
    }

    bytes
}

#[cfg(feature = "aes-drbg")]
#[test]
fn test_kat_data_analysis() {
    println!("=== KAT Data Analysis ===");

    // From the official KAT file (count=0):
    let kat_seed = hex_to_bytes(
        "061550234D158C5EC95595FE04EF7A25767F2E24CC2BC479D09D86DC9ABCFDE7056A8C266F9EF97ED08541DBD2E1FFA1",
    );
    let kat_pk = hex_to_bytes(
        "",
    );
    let kat_sk = hex_to_bytes(
        "",
    );

    println!("KAT seed (48 bytes): {:02x?}", kat_seed);
    println!("KAT public key (first 64 bytes): {:02x?}", &kat_pk[..64]);
    println!("KAT secret key (first 64 bytes): {:02x?}", &kat_sk[..64]);

    // Extract expected values from KAT data
    let expected_seed_dk = &kat_sk[0..32]; // First 32 bytes of secret key
    let expected_seed_ek = &kat_pk[0..32]; // First 32 bytes of public key

    println!("\nExpected values from KAT:");
    println!("seed_dk (from sk): {:02x?}", expected_seed_dk);
    println!("seed_ek (from pk): {:02x?}", expected_seed_ek);

    // Now test our implementation
    println!("\n=== Testing Our Implementation ===");
    let kat_seed_array: [u8; 48] = kat_seed.try_into().unwrap();
    let mut rng = Aes256CtrDrbg::instantiate(&kat_seed_array);

    let mut seed_dk = [0u8; 32];
    let mut seed_ek = [0u8; 32];
    rng.fill_bytes(&mut seed_dk);
    rng.fill_bytes(&mut seed_ek);

    println!("Our generated values:");
    println!("seed_dk: {:02x?}", seed_dk);
    println!("seed_ek: {:02x?}", seed_ek);

    println!("\nComparison:");
    println!("seed_dk match: {}", seed_dk == expected_seed_dk);
    println!("seed_ek match: {}", seed_ek == expected_seed_ek);

    if seed_dk == expected_seed_dk && seed_ek == expected_seed_ek {
        println!("✅ PERFECT MATCH! Our implementation is 100% correct!");
    } else {
        println!("❌ Still not matching");
        if seed_dk != expected_seed_dk {
            println!("  seed_dk differs");
        }
        if seed_ek != expected_seed_ek {
            println!("  seed_ek differs");
        }
    }
}

#[cfg(not(feature = "aes-drbg"))]
#[test]
fn test_feature_disabled() {
    println!("=== AES-CTR-DRBG Feature Disabled Test ===");
    println!("✅ Feature disabled test passed - aes-drbg feature is not enabled");
}
